                "description": "Hash/fingerprint of chunk content to detect drift."
              }
            }
          }
        },
        "citations": {
          "type": "array",
          "description": "Evidence bindings from content fields to chunks.",
          "items": {
            "type": "object",
            "additionalProperties": false,
            "required": ["field_path", "evidence_spans", "kind"],
            "properties": {
              "field_path": {
                "type": "string",
                "description": "JSON pointer-like path, e.g. content.intent.problem or content.procedure[2].instructions[0]"
              },
