## 2) Consistency Contract 默认规则集（建议文件：`consistency_contract.default.v0.1.yaml`）

> 这是“默认策略”。你可以允许每个 skill 覆盖它（例如某些 skill 允许 scope 变化更频繁）。

```yaml
contract_version: "0.1.0"

# 说明：
# - invariants: 默认锁定或强约束的字段（保持前后一致的核心）
# - allowed_changes: 允许变化的字段（但仍需 evidence 或明确标注 inference/assumption）
# - major_change_triggers: 只要触发，就必须 bump major（X.y.z -> (X+1).0.0）并写原因
# - gates: 门禁阈值（pass 才能 released，否则 draft）

invariants:
  - rule_id: INV-INTENT
    paths:
      - "content.intent.problem"
      - "content.intent.success_criteria"
    policy: major_if_changed
    notes: "Intent 变化意味着 skill 本质改变，默认 major。"

  - rule_id: INV-SCOPE
    paths:
      - "content.scope.in_scope"
      - "content.scope.out_of_scope"
    policy: major_if_changed
    notes: "Scope/Non-goals 改动默认 major，除非只是补充 out_of_scope（可走 minor）。"

  - rule_id: INV-IO
    paths:
      - "content.io_contract.inputs"
      - "content.io_contract.outputs"
    policy: major_if_changed
    notes: "I/O 契约一旦变更，依赖者会被破坏，默认 major。"

  - rule_id: INV-VALIDATION-CORE
    paths:
      - "content.validation.acceptance_checks"
    policy: allow_add_only
    notes: "验收项允许增补，不允许无理由删除或弱化。删除需走 major + 替代项说明。"

  - rule_id: INV-TERMS
    paths:
      - "content.terminology"
    policy: allow_edit
    notes: "术语允许完善定义，但同一 term 不得出现互相矛盾定义；出现冲突则 fail contract gate。"

allowed_changes:
  - rule_id: ALW-PROCEDURE
    paths:
      - "content.procedure"
    policy: allow_edit
    notes: "步骤允许细化/重排；但必须保持与 intent/validation 自洽，且关键步骤不得无 evidence。"

  - rule_id: ALW-PREREQ
    paths:
      - "content.prerequisites"
    policy: allow_edit
    notes: "前置条件可补充或调整；若新增高门槛权限/环境，建议触发 minor 并明确影响面。"

  - rule_id: ALW-EDGE
    paths:
      - "content.edge_cases"
    policy: allow_add_only
    notes: "边界与风险默认只增补；若删除需提供 reason 且 diff 可解释。"

  - rule_id: ALW-ARTIFACTS
    paths:
      - "content.artifacts"
    policy: allow_edit
    notes: "产物可增删；删除需说明替代路径或为何不再需要。"

  - rule_id: ALW-OPENQ
    paths:
      - "content.open_questions"
    policy: allow_edit
    notes: "开放问题可增删；删除应对应新增 evidence 或结论已落地。"

major_change_triggers:
  - rule_id: MAJ-INTENT-CHANGE
    paths:
      - "content.intent.problem"
    policy: major_if_changed
    notes: "问题定义变更 -> major。"

  - rule_id: MAJ-IO-BREAKING
    paths:
      - "content.io_contract.inputs"
      - "content.io_contract.outputs"
    policy: major_if_changed
    notes: "I/O 破坏性变更 -> major。"

  - rule_id: MAJ-VALIDATION-REMOVAL
    paths:
      - "content.validation.acceptance_checks"
    policy: major_if_changed
    notes: "删除/弱化验收 -> major（并要求替代项）。"

  - rule_id: MAJ-SCOPE-REDUCE
    paths:
      - "content.scope.in_scope"
    policy: major_if_changed
    notes: "缩小/改变适用范围 -> major（因为用户预期会被破坏）。"

gates:
  schema_gate:
    enabled: true
    min_score: 1.0
    required_fields:
      - "skill_id"
      - "schema_version"
      - "versions.current"
      - "versions.baseline"
      - "content.name"
      - "content.intent.problem"
      - "content.procedure"
      - "content.validation.acceptance_checks"

  evidence_gate:
    enabled: true
    min_score: 0.80
    required_fields:
      - "content.intent.problem"
      - "content.scope.in_scope"
      - "content.procedure"
      - "content.validation.acceptance_checks"
    # 解释建议（由实现层执行）：
    # - required_fields 对应的 citations 覆盖率必须 >= min_score
    # - citations.kind 为 inference/assumption 的占比不得超过 0.20（否则降级 draft）

  contract_gate:
    enabled: true
    min_score: 0.90
    required_fields: []
    # 解释建议：
    # - 任一 invariants 被违反但未 bump major 或无 reason -> fail
    # - 术语冲突/自相矛盾 -> fail

  diff_gate:
    enabled: true
    min_score: 0.80
    required_fields: []
    # 解释建议：
    # - diff 必须可解释：reason 与输入变化或用户指令能对齐
    # - remove 操作必须携带 reason（在 history.reason 里体现）

  regression_gate:
    enabled: false
    min_score: 1.0
    required_fields: []
    # 可选：当存在 tests 时启用
```

